import{_ as i,a as e,b as l}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as o,o as t,c as r,a2 as p}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"认证管理和登录设备管理","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Safety/authentication-and-login-devices.md","filePath":"cn/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),h={name:"cn/Safety/authentication-and-login-devices.md"};function n(d,a,c,s,u,b){return t(),r("div",null,[...a[0]||(a[0]=[p('<h1 id="认证管理和登录设备管理" tabindex="-1">认证管理和登录设备管理 <a class="header-anchor" href="#认证管理和登录设备管理" aria-label="Permalink to &quot;认证管理和登录设备管理&quot;">​</a></h1><p>安全设置里的“认证管理”和“登录设备管理”，主要用来保护你的图床后台、上传入口和 WebDAV 访问。</p><p>你可以在这里设置访问密码，也可以查看哪些设备登录过，并在需要时让旧设备下线。</p><h2 id="功能入口" tabindex="-1">功能入口 <a class="header-anchor" href="#功能入口" aria-label="Permalink to &quot;功能入口&quot;">​</a></h2><p>进入后台后，打开：</p><p>系统配置 → 安全设置</p><p>页面里可以看到两块主要内容：</p><ul><li>认证管理</li><li>登录设备管理</li></ul><p><img src="'+i+'" alt="认证管理界面" loading="lazy"></p><h2 id="认证管理是做什么的" tabindex="-1">认证管理是做什么的 <a class="header-anchor" href="#认证管理是做什么的" aria-label="Permalink to &quot;认证管理是做什么的&quot;">​</a></h2><p>认证管理用来设置访问凭据。</p><p>目前分为两类：</p><ul><li>用户端认证</li><li>管理端认证</li></ul><h2 id="用户端认证" tabindex="-1">用户端认证 <a class="header-anchor" href="#用户端认证" aria-label="Permalink to &quot;用户端认证&quot;">​</a></h2><p>用户端认证对应“上传密码”。</p><p>设置上传密码后，普通用户访问上传页面时需要输入密码。适合你不想让任何人都能直接上传图片的场景。</p><p><img src="'+e+'" alt="用户端登录界面" loading="lazy"></p><h3 id="设置上传密码" tabindex="-1">设置上传密码 <a class="header-anchor" href="#设置上传密码" aria-label="Permalink to &quot;设置上传密码&quot;">​</a></h3><p>如果填写上传密码：</p><ul><li>用户进入上传页面时需要输入密码。</li><li>密码正确后才能继续使用上传功能。</li><li>如果开启了“用户端设备会话”，系统会记录这个用户端设备。</li></ul><p>如果你修改了上传密码，旧的用户端登录状态会失效，用户需要重新输入新密码。</p><h2 id="管理端认证" tabindex="-1">管理端认证 <a class="header-anchor" href="#管理端认证" aria-label="Permalink to &quot;管理端认证&quot;">​</a></h2><p>管理端认证对应“用户名”和“密码”。</p><p>这是后台管理页面的登录保护。建议正式使用时一定要设置。</p><p><img src="'+l+'" alt="管理端登录界面" loading="lazy"></p><h3 id="设置管理端认证" tabindex="-1">设置管理端认证 <a class="header-anchor" href="#设置管理端认证" aria-label="Permalink to &quot;设置管理端认证&quot;">​</a></h3><p>如果填写用户名和密码：</p><ul><li>进入后台需要登录。</li><li>登录成功后会记录管理端设备。</li><li>可以在登录设备管理里查看、清理或强制下线设备。</li></ul><p>如果你修改了管理端用户名或密码，旧的后台登录状态会失效，需要重新登录。</p><h2 id="登录设备管理是做什么的" tabindex="-1">登录设备管理是做什么的 <a class="header-anchor" href="#登录设备管理是做什么的" aria-label="Permalink to &quot;登录设备管理是做什么的&quot;">​</a></h2><p>登录设备管理用来查看和管理已经登录过的设备。</p><p>它可以帮助你确认：</p><ul><li>哪些设备登录过后台。</li><li>哪些设备访问过用户端。</li><li>哪些 WebDAV 客户端连接过站点。</li><li>某个设备是否还有效。</li><li>是否需要让旧设备下线。</li></ul><p>页面里有三个页签：</p><ul><li>管理端</li><li>用户端</li><li>WebDAV</li></ul><h2 id="全局-cookie-安全设置" tabindex="-1">全局 Cookie 安全设置 <a class="header-anchor" href="#全局-cookie-安全设置" aria-label="Permalink to &quot;全局 Cookie 安全设置&quot;">​</a></h2><p>登录设备管理顶部有一组全局 Cookie 设置。</p><h3 id="用户端-cookie-有效期" tabindex="-1">用户端 Cookie 有效期 <a class="header-anchor" href="#用户端-cookie-有效期" aria-label="Permalink to &quot;用户端 Cookie 有效期&quot;">​</a></h3><p>控制用户端登录状态可以保留多少天。</p><p>比如设置为 14 天，用户端登录成功后，在 14 天内通常不需要重复输入上传密码。</p><h3 id="管理端-cookie-有效期" tabindex="-1">管理端 Cookie 有效期 <a class="header-anchor" href="#管理端-cookie-有效期" aria-label="Permalink to &quot;管理端 Cookie 有效期&quot;">​</a></h3><p>控制后台管理端登录状态可以保留多少天。</p><p>比如设置为 14 天，管理员登录后台后，在 14 天内通常不需要重复登录。</p><h3 id="secure-模式" tabindex="-1">Secure 模式 <a class="header-anchor" href="#secure-模式" aria-label="Permalink to &quot;Secure 模式&quot;">​</a></h3><p>开启 Secure 模式后，浏览器只会在 HTTPS 访问时携带登录 Cookie。</p><p>建议正式 HTTPS 站点开启。</p><p>如果你是在本地 HTTP 地址调试，不建议开启，否则可能出现“登录成功但刷新后又退出”的情况。</p><h2 id="管理端登录设备" tabindex="-1">管理端登录设备 <a class="header-anchor" href="#管理端登录设备" aria-label="Permalink to &quot;管理端登录设备&quot;">​</a></h2><p>管理端页签显示后台登录设备。</p><p>只有设置了管理端用户名或密码，并成功登录后台后，才会出现设备记录。</p><p>设备卡片里会显示：</p><ul><li>设备和浏览器信息</li><li>首次登录 IP</li><li>最近活跃 IP</li><li>登录时间</li><li>最后活跃时间</li><li>过期时间</li><li>当前状态</li></ul><p>如果看到陌生设备，可以点击“强制下线”让它失效。</p><h2 id="清理旧设备" tabindex="-1">清理旧设备 <a class="header-anchor" href="#清理旧设备" aria-label="Permalink to &quot;清理旧设备&quot;">​</a></h2><p>“清理旧设备”用于批量清理当前类型下的旧登录记录。</p><p>如果你怀疑账号在其它设备上仍然保持登录，可以使用这个按钮快速清理。</p><h2 id="强制下线" tabindex="-1">强制下线 <a class="header-anchor" href="#强制下线" aria-label="Permalink to &quot;强制下线&quot;">​</a></h2><p>“强制下线”用于让某一个设备失效。</p><p>被强制下线后：</p><ul><li>管理端设备需要重新登录后台。</li><li>用户端设备需要重新输入上传密码。</li><li>WebDAV 客户端需要重新认证。</li></ul><p>如果设备已经过期或已经失效，也可以清理掉对应记录。</p><h2 id="退出当前设备" tabindex="-1">退出当前设备 <a class="header-anchor" href="#退出当前设备" aria-label="Permalink to &quot;退出当前设备&quot;">​</a></h2><p>当前设备卡片上会显示“当前设备”标记。</p><p>点击退出当前设备后：</p><ul><li>管理端会退出当前后台登录。</li><li>用户端会退出当前用户端登录。</li></ul><p>退出后需要重新登录才能继续使用对应功能。</p>',66)])])}const f=o(h,[["render",n]]);export{q as __pageData,f as default};
